-- =============================================================================
-- Custom PL/pgSQL Functions (from case.sql)
-- =============================================================================

CREATE OR REPLACE FUNCTION get_case_statistics(user_id TEXT DEFAULT NULL)
RETURNS TABLE (
    status "CaseStatus",
    count BIGINT,
    overdue_count BIGINT
)
LANGUAGE plpgsql
AS $$
BEGIN
    RETURN QUERY
    SELECT
        c.status,
        COUNT(*)::BIGINT as count,
        COUNT(*) FILTER (
            WHERE c.deadline IS NOT NULL
            AND c.deadline < CURRENT_TIMESTAMP
            AND c.status NOT IN ('CLOSED', 'CANCELLED')
        )::BIGINT as overdue_count
    FROM cases c
    WHERE user_id IS NULL OR c."assignedTo" = user_id
    GROUP BY c.status;
END;
$$;

CREATE OR REPLACE FUNCTION get_upcoming_deadline_cases(
    days_ahead INT DEFAULT 7,
    user_id TEXT DEFAULT NULL
)
RETURNS TABLE (
    id TEXT,
    title TEXT,
    status "CaseStatus",
    priority "CasePriority",
    deadline TIMESTAMP(3),
    days_remaining INT
)
LANGUAGE plpgsql
AS $$
BEGIN
    RETURN QUERY
    SELECT
        c.id,
        c.title,
        c.status,
        c.priority,
        c.deadline,
        EXTRACT(DAY FROM c.deadline - CURRENT_TIMESTAMP)::INT as days_remaining
    FROM cases c
    WHERE c.deadline IS NOT NULL
        AND c.deadline <= (CURRENT_TIMESTAMP + (days_ahead || ' days')::INTERVAL)
        AND c.status NOT IN ('CLOSED', 'CANCELLED')
        AND (user_id IS NULL OR c."assignedTo" = user_id)
    ORDER BY c.deadline ASC;
END;
$$;

CREATE OR REPLACE FUNCTION get_case_task_progress(case_id TEXT)
RETURNS TABLE (
    total_tasks BIGINT,
    completed_tasks BIGINT,
    pending_tasks BIGINT,
    overdue_tasks BIGINT,
    progress_percentage DECIMAL(5,2)
)
LANGUAGE plpgsql
AS $$
BEGIN
    RETURN QUERY
    SELECT
        COUNT(*)::BIGINT as total_tasks,
        COUNT(*) FILTER (WHERE ct.status = 'COMPLETED')::BIGINT as completed_tasks,
        COUNT(*) FILTER (WHERE ct.status IN ('PENDING', 'IN_PROGRESS'))::BIGINT as pending_tasks,
        COUNT(*) FILTER (
            WHERE ct."dueDate" < CURRENT_TIMESTAMP
            AND ct.status NOT IN ('COMPLETED', 'CANCELLED')
        )::BIGINT as overdue_tasks,
        CASE
            WHEN COUNT(*) = 0 THEN 0.00
            ELSE ROUND((COUNT(*) FILTER (WHERE ct.status = 'COMPLETED')::DECIMAL / COUNT(*)) * 100, 2)
        END as progress_percentage
    FROM case_tasks ct
    WHERE ct."caseId" = case_id;
END;
$$;

-- =============================================================================
-- Custom PL/pgSQL Functions (from case-document.sql)
-- Rewritten: UUID -> TEXT for all params and return types
-- =============================================================================

CREATE OR REPLACE FUNCTION audit_case_document_changes()
RETURNS TRIGGER AS $$
BEGIN
  IF (TG_OP = 'INSERT') THEN
    INSERT INTO case_document_audit (
      id, document_id, tenant_id, event_type, user_id, metadata
    ) VALUES (
      gen_random_uuid()::TEXT,
      NEW.id,
      NEW.tenant_id,
      'CREATED',
      NEW.created_by,
      jsonb_build_object(
        'title', NEW.title,
        'document_type', NEW.document_type,
        'classification', NEW.classification,
        'version', NEW.version_major || '.' || NEW.version_minor || '.' || NEW.version_patch
      )
    );

  ELSIF (TG_OP = 'UPDATE') THEN
    IF (OLD.status IS DISTINCT FROM NEW.status) THEN
      INSERT INTO case_document_audit (
        id, document_id, tenant_id, event_type, user_id, changes
      ) VALUES (
        gen_random_uuid()::TEXT,
        NEW.id,
        NEW.tenant_id,
        CASE NEW.status
          WHEN 'UNDER_REVIEW' THEN 'SUBMITTED_FOR_REVIEW'
          WHEN 'APPROVED' THEN 'APPROVED'
          WHEN 'SIGNED' THEN 'SIGNED'
          WHEN 'ARCHIVED' THEN 'ARCHIVED'
          ELSE 'UPDATED'
        END,
        NEW.updated_by,
        jsonb_build_object('old_status', OLD.status, 'new_status', NEW.status)
      );
    END IF;

    IF (OLD.retention_until IS DISTINCT FROM NEW.retention_until) THEN
      IF (NEW.retention_until IS NOT NULL) THEN
        INSERT INTO case_document_audit (
          id, document_id, tenant_id, event_type, user_id, metadata
        ) VALUES (
          gen_random_uuid()::TEXT,
          NEW.id,
          NEW.tenant_id,
          'LEGAL_HOLD_PLACED',
          NEW.updated_by,
          jsonb_build_object('retention_until', NEW.retention_until)
        );
      ELSE
        INSERT INTO case_document_audit (
          id, document_id, tenant_id, event_type, user_id, metadata
        ) VALUES (
          gen_random_uuid()::TEXT,
          NEW.id,
          NEW.tenant_id,
          'LEGAL_HOLD_RELEASED',
          NEW.updated_by,
          jsonb_build_object('previous_retention_until', OLD.retention_until)
        );
      END IF;
    END IF;

    IF (OLD.deleted_at IS NULL AND NEW.deleted_at IS NOT NULL) THEN
      INSERT INTO case_document_audit (
        id, document_id, tenant_id, event_type, user_id, metadata
      ) VALUES (
        gen_random_uuid()::TEXT,
        NEW.id,
        NEW.tenant_id,
        'DELETED',
        NEW.updated_by,
        jsonb_build_object('deleted_at', NEW.deleted_at)
      );
    END IF;

  END IF;

  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

CREATE OR REPLACE FUNCTION audit_case_document_acl_changes()
RETURNS TRIGGER AS $$
BEGIN
  IF (TG_OP = 'INSERT') THEN
    INSERT INTO case_document_audit (
      id, document_id, tenant_id, event_type, user_id, metadata
    ) VALUES (
      gen_random_uuid()::TEXT,
      NEW.document_id,
      NEW.tenant_id,
      'ACCESS_GRANTED',
      NEW.granted_by,
      jsonb_build_object(
        'principal_id', NEW.principal_id,
        'principal_type', NEW.principal_type,
        'access_level', NEW.access_level,
        'expires_at', NEW.expires_at
      )
    );

  ELSIF (TG_OP = 'DELETE') THEN
    INSERT INTO case_document_audit (
      id, document_id, tenant_id, event_type, user_id, metadata
    ) VALUES (
      gen_random_uuid()::TEXT,
      OLD.document_id,
      OLD.tenant_id,
      'ACCESS_REVOKED',
      (SELECT updated_by FROM case_documents WHERE id = OLD.document_id),
      jsonb_build_object(
        'principal_id', OLD.principal_id,
        'principal_type', OLD.principal_type,
        'access_level', OLD.access_level
      )
    );
  END IF;

  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

CREATE OR REPLACE FUNCTION get_document_version_history(p_document_id TEXT)
RETURNS TABLE (
  id TEXT,
  version TEXT,
  status TEXT,
  created_at TIMESTAMP(3),
  created_by TEXT,
  is_latest BOOLEAN
) AS $$
BEGIN
  RETURN QUERY
  WITH RECURSIVE version_tree AS (
    SELECT
      d.id,
      d.version_major || '.' || d.version_minor || '.' || d.version_patch AS version,
      d.status,
      d.created_at,
      d.created_by,
      d.is_latest_version AS is_latest,
      d.parent_version_id
    FROM case_documents d
    WHERE d.id = p_document_id

    UNION ALL

    SELECT
      d.id,
      d.version_major || '.' || d.version_minor || '.' || d.version_patch AS version,
      d.status,
      d.created_at,
      d.created_by,
      d.is_latest_version AS is_latest,
      d.parent_version_id
    FROM case_documents d
    INNER JOIN version_tree vt ON d.id = vt.parent_version_id
  )
  SELECT
    vt.id,
    vt.version,
    vt.status,
    vt.created_at,
    vt.created_by,
    vt.is_latest
  FROM version_tree vt
  ORDER BY vt.created_at DESC;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

CREATE OR REPLACE FUNCTION user_has_document_access(
  p_user_id TEXT,
  p_document_id TEXT,
  p_required_level VARCHAR(20)
)
RETURNS BOOLEAN AS $$
DECLARE
  v_access_level VARCHAR(20);
  v_level_order TEXT[] := ARRAY['NONE', 'VIEW', 'COMMENT', 'EDIT', 'ADMIN'];
  v_user_level_index INT;
  v_required_level_index INT;
BEGIN
  SELECT access_level INTO v_access_level
  FROM case_document_acl
  WHERE document_id = p_document_id
    AND principal_id = p_user_id
    AND (expires_at IS NULL OR expires_at > NOW());

  IF v_access_level IS NULL THEN
    RETURN FALSE;
  END IF;

  SELECT array_position(v_level_order, v_access_level) INTO v_user_level_index;
  SELECT array_position(v_level_order, p_required_level) INTO v_required_level_index;

  RETURN v_user_level_index >= v_required_level_index;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- =============================================================================
-- Audit Triggers (from case-document.sql)
-- =============================================================================

CREATE TRIGGER trg_audit_case_documents
  AFTER INSERT OR UPDATE ON case_documents
  FOR EACH ROW
  EXECUTE FUNCTION audit_case_document_changes();

CREATE TRIGGER trg_audit_case_document_acl
  AFTER INSERT OR DELETE ON case_document_acl
  FOR EACH ROW
  EXECUTE FUNCTION audit_case_document_acl_changes();
